// Helper: get only daily free full meals (for survival-first use case)
export const SURVIVAL_PRIORITY = PLACES_SEED.filter(
  (p) => p.cost_type === 'free' && p.frequency === 'daily' && p.food_type === 'annadanam',
);

export const getByCategory = (cat: Category) => PLACES_SEED.filter((p) => p.category === cat);

export const getWithCoords = () =>
  PLACES_SEED.filter((p) => p.latitude !== null && p.longitude !== null);
